// SPDX-License-Identifier: BUSL-1.1
pragma solidity ^0.8.24;

/// @title IUnlloo
/// @author Unlloo Protocol Team
/// @notice Canonical public interface for the Unlloo undercollateralized lending protocol
/// @dev This interface defines the complete public API for the Unlloo lending protocol.
///      Internal storage layout is intentionally NOT exposed to allow upgrade flexibility.
///
/// ## Design Principles
///
/// 1. Simple Interest Model: Interest is calculated linearly and non-compounding.
///    Formula: `interest = principal × rate × time / (BLOCKS_PER_YEAR × BPS_DENOMINATOR)`
///
/// 2. Single Borrow Per Loan: Once a loan is approved, the borrower can execute
///    `borrow()` exactly once. Partial borrows are allowed but unused amounts are forfeited.
///
/// 3. One Active Loan Per Borrower: A borrower may have at most one loan in
///    `Active` or `UnpaidDebt` status at any time.
///
/// 4. Interest on Principal Only: Interest accrues solely on the outstanding
///    principal balance, not on previously accrued interest.
///
/// 5. Protocol Fee on Interest: The protocol fee is a percentage of interest
///    paid, not principal. Fee = interestPaid × protocolFeePercentage / 100
///
/// 6. ETH for Operations Only: ETH received by the contract is for gas/operational
///    purposes. All lending/borrowing uses ERC20 tokens exclusively.
///
/// ## Token Decimals
///
/// All amounts are denominated in the underlying ERC20 token's decimals unless
/// explicitly stated otherwise. Rates are in basis points (BPS, 1 BPS = 0.01%).
///
/// @custom:security-contact security@unlloo.com
interface IUnlloo {
    // =============================================================
    //                           ENUMS
    // =============================================================

    /// @notice Lifecycle states for a loan
    /// @dev State transitions:
    ///   Pending → Approved (admin approves)
    ///   Pending → Rejected (admin rejects)
    ///   Approved → Active (borrower calls borrow())
    ///   Active → Repaid (borrower repays in full)
    ///   Active → UnpaidDebt (deadline passes without full repayment)
    ///   UnpaidDebt → Repaid (borrower repays outstanding debt)
    enum LoanStatus {
        /// @notice Loan request submitted, awaiting admin decision
        Pending,
        /// @notice Loan approved by admin, awaiting borrower to call borrow()
        Approved,
        /// @notice Funds disbursed, loan is active with accruing interest
        Active,
        /// @notice Loan past deadline with outstanding balance
        UnpaidDebt,
        /// @notice Loan request rejected by admin
        Rejected,
        /// @notice Loan fully repaid (principal + interest)
        Repaid
    }

    // =============================================================
    //                           STRUCTS
    // =============================================================

    /// @notice Canonical loan record using the simple-interest model
    /// @dev This struct contains all state for a single loan throughout its lifecycle.
    ///      Storage is optimized: addresses and status are packed where possible.
    ///      All block numbers reference the chain specified by `chainId`.
    struct Loan {
        /// @notice Unique sequential identifier (1-indexed, 0 is invalid)
        uint256 loanId;

        /// @notice Address of the borrower who requested the loan
        address borrower;

        /// @notice Current lifecycle status of the loan
        /// @dev See `LoanStatus` enum for valid transitions
        LoanStatus status;

        /// @notice Self-reported wallet reputation score (0-1000)
        /// @dev Advisory only; actual credit decisions may use external oracles
        uint16 walletReputation;

        /// @notice Loan amount in token decimals
        /// @dev Set during approval; borrower may borrow less but not more
        uint256 loanAmount;

        /// @notice Requested loan duration in blocks
        /// @dev Must be within [MIN_LOAN_DURATION_BLOCKS, MAX_LOAN_DURATION_BLOCKS]
        uint256 loanDurationBlocks;

        /// @notice Chain ID where the loan was requested
        /// @dev Captured at request time for cross-chain safety
        uint256 chainId;

        /// @notice Block number when loan request was submitted
        uint256 requestBlock;

        /// @notice Block number when loan was approved (0 if not approved)
        uint256 approvalBlock;

        /// @notice ERC20 token address used for this loan
        /// @dev Must be a whitelisted token with an active liquidity pool
        address token;

        /// @notice Current outstanding principal balance in token decimals
        /// @dev Decreases as borrower makes repayments
        uint256 principal;

        /// @notice Cumulative amount repaid (principal + interest) in token decimals
        uint256 amountRepaid;

        /// @notice Block number when borrow() was executed (0 if not borrowed)
        /// @dev Interest accrual begins from this block
        uint256 startBlock;

        /// @notice Block number by which full repayment is due
        /// @dev Calculated as: startBlock + loanDurationBlocks
        uint256 deadlineBlock;

        /// @notice Cumulative protocol fees collected from this loan in token decimals
        /// @dev Fee = protocolFeePercentage × interestPaid / 100
        uint256 protocolFee;

        /// @notice Accrued but unpaid interest in token decimals
        /// @dev Updated on each accrual; simple interest formula applied
        uint256 interestAccrued;

        /// @notice Fixed annual borrow rate in basis points (1 BPS = 0.01%)
        /// @dev Locked at borrow time from the current pool utilization rate
        uint256 borrowRateBps;

        /// @notice Block number when interest was last accrued
        /// @dev Used to calculate elapsed blocks for next accrual
        uint256 lastAccrualBlock;
    }

    /// @notice Aggregate state for a token's liquidity pool
    /// @dev Each supported ERC20 token has exactly one pool
    struct LiquidityPool {
        /// @notice ERC20 token address for this pool
        address token;

        /// @notice Total liquidity deposited by lenders in token decimals
        /// @dev Includes both available and borrowed amounts
        uint256 totalLiquidity;

        /// @notice Amount currently lent out to borrowers in token decimals
        /// @dev Available liquidity = totalLiquidity - borrowedAmount
        uint256 borrowedAmount;
    }

    /// @notice Individual lender's position within a token pool
    /// @dev Tracks deposits and withdrawal timing for yield calculations
    struct LenderPosition {
        /// @notice Address of the lender
        address lender;

        /// @notice ERC20 token address of the pool
        address token;

        /// @notice Current deposited amount in token decimals
        /// @dev Tracks principal only; yield is calculated separately
        uint256 depositedAmount;

        /// @notice Block number of the initial deposit
        uint256 depositBlock;

        /// @notice Block number of the most recent withdrawal (0 if never withdrawn)
        uint256 lastWithdrawBlock;
    }

    /// @notice Interest rate curve parameters for a pool
    /// @dev Per-pool configurable rate model with protocol fee
    struct RateCurveParams {
        /// @notice Base interest rate in basis points (e.g., 200 = 2%)
        uint256 baseRateBps;

        /// @notice Optimal utilization kink point in basis points (e.g., 8000 = 80%)
        uint256 optimalUtilizationBps;

        /// @notice Interest rate slope below optimal utilization in basis points
        uint256 slope1Bps;

        /// @notice Interest rate slope above optimal utilization in basis points
        uint256 slope2Bps;

        /// @notice Protocol fee on interest in basis points (e.g., 2500 = 25%)
        uint256 protocolFeeBps;
    }

    // =============================================================
    //                           EVENTS
    // =============================================================

    // ---------------------- Loan Lifecycle Events ----------------------

    /// @notice Emitted when a borrower submits a new loan request
    /// @param loanId Unique identifier assigned to the loan (indexed for filtering)
    /// @param borrower Address of the borrower submitting the request (indexed)
    /// @param walletReputation Self-reported reputation score (0-1000)
    /// @param loanAmount Requested loan amount in token decimals
    /// @param loanDurationBlocks Requested loan duration in blocks
    /// @param blockNumber Block number when request was submitted
    event LoanRequestSubmitted(
        uint256 indexed loanId,
        address indexed borrower,
        uint16 walletReputation,
        uint256 loanAmount,
        uint256 loanDurationBlocks,
        uint256 blockNumber
    );

    /// @notice Emitted when an admin approves a pending loan request
    /// @param loanId Loan identifier being approved (indexed)
    /// @param borrower Address of the borrower whose loan was approved (indexed)
    /// @param approvalBlock Block number when approval occurred
    event LoanRequestApproved(
        uint256 indexed loanId,
        address indexed borrower,
        uint256 approvalBlock
    );

    /// @notice Emitted when an admin rejects a pending loan request
    /// @param loanId Loan identifier being rejected (indexed)
    /// @param borrower Address of the borrower whose loan was rejected (indexed)
    /// @param rejectionBlock Block number when rejection occurred
    event LoanRequestRejected(
        uint256 indexed loanId,
        address indexed borrower,
        uint256 rejectionBlock
    );

    /// @notice Emitted when an approved loan is executed (funds disbursed)
    /// @dev `initialOwed` equals `principal` at borrow time (no interest yet)
    /// @param loanId Loan identifier being borrowed (indexed)
    /// @param borrower Address receiving the funds (indexed)
    /// @param token ERC20 token address being borrowed
    /// @param principal Amount of tokens borrowed
    /// @param initialOwed Initial amount owed (equals principal, no interest yet)
    /// @param startBlock Block number when borrowing occurred (interest starts)
    event LoanBorrowed(
        uint256 indexed loanId,
        address indexed borrower,
        address token,
        uint256 principal,
        uint256 initialOwed,
        uint256 startBlock
    );

    /// @notice Emitted on each loan repayment (partial or full)
    /// @param loanId Loan identifier being repaid (indexed)
    /// @param borrower Address making the repayment (indexed)
    /// @param token ERC20 token address being repaid
    /// @param repaymentAmount Amount repaid in this transaction
    /// @param remainingBalance Outstanding balance after repayment (0 if fully repaid)
    /// @param blockNumber Block number when repayment occurred
    event LoanRepaid(
        uint256 indexed loanId,
        address indexed borrower,
        address token,
        uint256 repaymentAmount,
        uint256 remainingBalance,
        uint256 blockNumber
    );

    /// @notice Emitted when a loan transitions to UnpaidDebt status
    /// @dev Triggered when deadline passes with outstanding balance
    /// @param loanId Loan identifier moved to unpaid debt (indexed)
    /// @param borrower Address of the delinquent borrower (indexed)
    /// @param deadlineBlock The original deadline block that was missed
    /// @param blockNumber Block number when status changed
    event LoanMovedToUnpaidDebt(
        uint256 indexed loanId,
        address indexed borrower,
        uint256 deadlineBlock,
        uint256 blockNumber
    );

    // ---------------------- Liquidity Events ----------------------

    /// @notice Emitted when a lender deposits liquidity into a pool
    /// @param lender Address of the depositor (indexed)
    /// @param token ERC20 token being deposited (indexed)
    /// @param amount Amount deposited in token decimals
    /// @param blockNumber Block number when deposit occurred
    event LiquidityDeposited(
        address indexed lender,
        address indexed token,
        uint256 amount,
        uint256 blockNumber
    );

    /// @notice Emitted when a lender withdraws liquidity from a pool
    /// @param lender Address of the withdrawer (indexed)
    /// @param token ERC20 token being withdrawn (indexed)
    /// @param principalAmount Principal portion of withdrawal
    /// @param interestAmount Earned interest portion of withdrawal
    /// @param totalAmount Total amount withdrawn (principal + interest)
    /// @param blockNumber Block number when withdrawal occurred
    event LiquidityWithdrawn(
        address indexed lender,
        address indexed token,
        uint256 principalAmount,
        uint256 interestAmount,
        uint256 totalAmount,
        uint256 blockNumber
    );

    // ---------------------- Admin Events ----------------------

    /// @notice Emitted when admin withdraws accumulated protocol fees
    /// @param admin Address of the admin making withdrawal (indexed)
    /// @param token ERC20 token being withdrawn (indexed)
    /// @param amount Amount of fees withdrawn
    /// @param blockNumber Block number when withdrawal occurred
    event ProtocolFeesWithdrawn(
        address indexed admin,
        address indexed token,
        uint256 amount,
        uint256 blockNumber
    );

    /// @notice Emitted when pool interest rate parameters are updated
    /// @param token Pool token address (indexed)
    /// @param baseRateBps New base rate in basis points
    /// @param optimalUtilizationBps New optimal utilization kink point
    /// @param slope1Bps New slope below optimal utilization
    /// @param slope2Bps New slope above optimal utilization
    /// @param protocolFeeBps New protocol fee in basis points
    /// @param blockNumber Block number when update occurred
    event InterestRatesUpdated(
        address indexed token,
        uint256 baseRateBps,
        uint256 optimalUtilizationBps,
        uint256 slope1Bps,
        uint256 slope2Bps,
        uint256 protocolFeeBps,
        uint256 blockNumber
    );

    /// @notice Emitted when a new liquidity pool is added for a token
    /// @param token ERC20 token address for the new pool (indexed)
    /// @param blockNumber Block number when pool was added
    event PoolAdded(address indexed token, uint256 blockNumber);

    /// @notice Emitted when a liquidity pool is removed
    /// @param token ERC20 token address of the removed pool (indexed)
    /// @param blockNumber Block number when pool was removed
    event PoolRemoved(address indexed token, uint256 blockNumber);

    /// @notice Emitted when pool loan limits are updated
    /// @param token ERC20 token address of the pool (indexed)
    /// @param minLoanAmount New minimum loan amount in token decimals
    /// @param maxLoanAmount New maximum loan amount in token decimals
    /// @param blockNumber Block number when limits were updated
    event PoolLoanLimitsUpdated(
        address indexed token,
        uint256 minLoanAmount,
        uint256 maxLoanAmount,
        uint256 blockNumber
    );

    /// @notice Emitted when ETH is received by the contract
    /// @dev ETH is for operational purposes only (gas sponsorship, etc.)
    /// @param sender Address that sent ETH (indexed)
    /// @param amount Amount of ETH received in wei
    /// @param blockNumber Block number when ETH was received
    event ETHReceived(address indexed sender, uint256 amount, uint256 blockNumber);

    /// @notice Emitted when admin withdraws ETH from the contract
    /// @dev ETH is operational only; not part of lending pools
    /// @param admin Address of the admin making withdrawal (indexed)
    /// @param amount Amount of ETH withdrawn in wei
    /// @param blockNumber Block number when withdrawal occurred
    event ETHWithdrawn(address indexed admin, uint256 amount, uint256 blockNumber);

    /// @notice Emitted during emergency token recovery
    /// @dev Only callable by admin in emergency situations
    /// @param token ERC20 token being recovered (indexed)
    /// @param amount Amount recovered in token decimals
    /// @param blockNumber Block number when emergency withdrawal occurred
    event EmergencyWithdraw(address indexed token, uint256 amount, uint256 blockNumber);

    // ---------------------- Configuration Events ----------------------

    /// @notice Emitted when minimum reputation threshold is updated
    /// @param oldMinReputation Previous minimum reputation value
    /// @param newMinReputation New minimum reputation value
    /// @param blockNumber Block number when update occurred
    event MinReputationUpdated(
        uint16 oldMinReputation,
        uint16 newMinReputation,
        uint256 blockNumber
    );

    /// @notice Emitted when cooldown period between loan requests is updated
    /// @param oldCooldownBlocks Previous cooldown in blocks
    /// @param newCooldownBlocks New cooldown in blocks
    /// @param blockNumber Block number when update occurred
    event CooldownBlocksUpdated(
        uint256 oldCooldownBlocks,
        uint256 newCooldownBlocks,
        uint256 blockNumber
    );

    // =============================================================
    //                       USER ACTIONS
    // =============================================================

    /// @notice Submit a new loan request to the protocol
    /// @dev Requirements:
    ///   - Caller must not have an active or unpaid loan
    ///   - Caller must be past cooldown period from last request
    ///   - Token must have an active liquidity pool
    ///   - Amount must be within pool's [minLoanAmount, maxLoanAmount]
    ///   - Duration must be within [MIN_LOAN_DURATION_BLOCKS, MAX_LOAN_DURATION_BLOCKS]
    ///   - walletReputation must be >= minReputation threshold
    /// @param walletReputation Self-reported reputation score (0-1000)
    /// @param token ERC20 token address to borrow
    /// @param loanAmount Requested loan amount in token decimals
    /// @param loanDurationBlocks Requested duration in blocks
    /// @return loanId Unique identifier assigned to the new loan request
    function submitLoanRequest(
        uint16 walletReputation,
        address token,
        uint256 loanAmount,
        uint256 loanDurationBlocks
    ) external returns (uint256 loanId);

    /// @notice Approve a pending loan request (admin only)
    /// @dev Transitions loan from Pending to Approved status.
    ///      The borrower then has APPROVED_LOAN_EXPIRY_BLOCKS to call borrow().
    /// @param loanId Identifier of the loan to approve
    function approveLoanRequest(uint256 loanId) external;

    /// @notice Reject a pending loan request (admin only)
    /// @dev Transitions loan from Pending to Rejected status (terminal).
    /// @param loanId Identifier of the loan to reject
    function rejectLoanRequest(uint256 loanId) external;

    /// @notice Execute borrowing on an approved loan
    /// @dev Requirements:
    ///   - Loan must be in Approved status
    ///   - Caller must be the loan's borrower
    ///   - tokenAmount must be > 0 and <= approved loanAmount
    ///   - Sufficient liquidity must be available in the pool
    ///   - Can only be called once per loan; unused approved amount is forfeited
    /// @param loanId Identifier of the approved loan
    /// @param tokenAmount Amount to borrow (may be less than approved amount)
    function borrow(uint256 loanId, uint256 tokenAmount) external;

    /// @notice Make a repayment on an active loan
    /// @dev Requirements:
    ///   - Loan must be in Active or UnpaidDebt status
    ///   - Caller must approve token transfer to contract
    ///   - Repayment is applied: interest first, then principal
    ///   - If full balance repaid, loan transitions to Repaid status
    /// @param loanId Identifier of the loan to repay
    /// @param amount Amount to repay in token decimals
    function repay(uint256 loanId, uint256 amount) external;

    /// @notice Deposit liquidity into a token pool to earn yield
    /// @dev Requirements:
    ///   - Token must have an active liquidity pool
    ///   - Caller must approve token transfer to contract
    ///   - Amount must be > 0
    /// @param token ERC20 token address to deposit
    /// @param amount Amount to deposit in token decimals
    function depositLiquidity(address token, uint256 amount) external;

    /// @notice Withdraw liquidity (principal + earned interest) from a pool
    /// @dev Requirements:
    ///   - Caller must have sufficient deposited balance
    ///   - Pool must have sufficient available liquidity (not borrowed)
    /// @param token ERC20 token address to withdraw
    /// @param amount Amount of principal to withdraw in token decimals
    function withdrawLiquidity(address token, uint256 amount) external;

    // =============================================================
    //                         VIEW FUNCTIONS
    // =============================================================

    // ---------------------- Loan Queries ----------------------

    /// @notice Retrieve complete loan data by ID
    /// @param loanId Identifier of the loan to query
    /// @return Loan struct containing all loan state
    function getLoan(uint256 loanId) external view returns (Loan memory);

    /// @notice Get the maximum approved amount for a loan
    /// @dev Returns 0 for non-approved loans or invalid IDs
    /// @param loanId Identifier of the loan to query
    /// @return Maximum amount the borrower can borrow (in token decimals)
    function getApprovedLoanAmount(uint256 loanId) external view returns (uint256);

    /// @notice Calculate current accrued interest for a loan
    /// @dev Uses simple interest: principal × rate × elapsedBlocks / (blocksPerYear × BPS)
    ///      Returns 0 for loans that haven't been borrowed yet
    /// @param loanId Identifier of the loan to query
    /// @return Accrued interest amount in token decimals
    function getAccruedInterest(uint256 loanId) external view returns (uint256);

    /// @notice Calculate total amount currently owed on a loan
    /// @dev Returns principal + accrued interest (simple interest model)
    /// @param loanId Identifier of the loan to query
    /// @return Total owed amount in token decimals
    function getTotalOwed(uint256 loanId) external view returns (uint256);

    /// @notice Calculate remaining balance after accounting for repayments
    /// @dev Returns totalOwed - amountRepaid; 0 if fully repaid
    /// @param loanId Identifier of the loan to query
    /// @return Remaining balance in token decimals
    function getRemainingBalance(uint256 loanId) external view returns (uint256);

    /// @notice Get all loan IDs for a specific borrower
    /// @dev Returns loans in all statuses (historical and current)
    /// @param borrower Address of the borrower to query
    /// @return Array of loan IDs belonging to the borrower
    function getLoansByBorrower(address borrower) external view returns (uint256[] memory);

    /// @notice Get loan IDs filtered by status with pagination
    /// @dev Useful for admin dashboards and indexers
    /// @param status LoanStatus to filter by
    /// @param offset Starting index for pagination
    /// @param limit Maximum number of results to return
    /// @return Array of loan IDs matching the status
    function getLoansByStatus(
        LoanStatus status,
        uint256 offset,
        uint256 limit
    ) external view returns (uint256[] memory);

    /// @notice Get the active or unpaid loan ID for a borrower
    /// @dev Returns 0 if the borrower has no Active or UnpaidDebt loan
    /// @param borrower Address of the borrower to query
    /// @return Loan ID if exists, 0 otherwise
    function getActiveLoanByBorrower(address borrower) external view returns (uint256);

    // ---------------------- Pool Queries ----------------------

    /// @notice Get aggregate pool state for a token
    /// @param token ERC20 token address of the pool
    /// @return LiquidityPool struct with current pool state
    function getLiquidityPool(address token) external view returns (LiquidityPool memory);

    /// @notice Get current loan limits for a pool
    /// @param token ERC20 token address of the pool
    /// @return minLoanAmount Current minimum loan amount in token decimals
    /// @return maxLoanAmount Current maximum loan amount in token decimals
    function getPoolLoanLimits(address token)
        external
        view
        returns (uint256 minLoanAmount, uint256 maxLoanAmount);

    /// @notice Get the interest rate curve parameters for a pool
    /// @param token Pool token address
    /// @return RateCurveParams struct with all rate parameters
    function getPoolRateCurve(address token) external view returns (RateCurveParams memory);

    /// @notice Calculate current borrow rate for a token pool
    /// @dev Rate is determined by pool utilization: borrowedAmount / totalLiquidity
    ///      Higher utilization = higher rates to incentivize deposits
    /// @param token ERC20 token address of the pool
    /// @return Current borrow rate in basis points (1 BPS = 0.01%)
    function calculateBorrowRate(address token) external view returns (uint256);

    /// @notice Get accumulated protocol fees for a token
    /// @dev Fees accumulate from interest payments; withdrawable by admin
    /// @param token ERC20 token address to query
    /// @return Accumulated fee amount in token decimals
    function getProtocolFees(address token) external view returns (uint256);

    /// @notice Get count of active lenders in a pool
    /// @dev A lender is "active" if their depositedAmount > 0
    /// @param token ERC20 token address of the pool
    /// @return Number of active lenders
    function getActiveLenderCount(address token) external view returns (uint256);

    // ---------------------- Lender Queries ----------------------

    /// @notice Get lender position with calculated interest
    /// @dev Returns deposited amount, accrued interest, and total withdrawable
    /// @param lender Address of the lender
    /// @param token ERC20 token address of the pool
    /// @return depositedAmount Principal deposited
    /// @return accruedInterest Interest earned so far
    /// @return totalWithdrawable Total amount available for withdrawal
    function getLenderPosition(
        address lender,
        address token
    ) external view returns (uint256 depositedAmount, uint256 accruedInterest, uint256 totalWithdrawable);

    // ---------------------- User State Queries ----------------------

    /// @notice Check if a user has any unpaid debt
    /// @dev Used to enforce one-active-loan-per-borrower rule
    /// @param user Address to check
    /// @return True if user has a loan in UnpaidDebt status
    function hasUnpaidDebt(address user) external view returns (bool);

    /// @notice Check if a user can submit a new loan request
    /// @dev Returns false if user has active loan, unpaid debt, or is in cooldown
    /// @param user Address to check
    /// @return True if user is eligible to submit a request
    function canSubmitRequest(address user) external view returns (bool);

    /// @notice Get the block number when cooldown ends for a user
    /// @dev Returns 0 if user has never made a request
    /// @param user Address to check
    /// @return Block number when cooldown expires (0 if no cooldown)
    function getCooldownEndBlock(address user) external view returns (uint256);

    // =============================================================
    //                        ADMIN ACTIONS
    // =============================================================

    /// @notice Pause all protocol operations (admin only)
    /// @dev When paused: no new loans, borrows, repayments, deposits, or withdrawals
    ///      Uses OpenZeppelin Pausable pattern
    function pause() external;

    /// @notice Resume protocol operations after pause (admin only)
    function unpause() external;

    /// @notice Withdraw ETH from contract (admin only)
    /// @dev ETH is for operational purposes only; not part of lending pools
    /// @param amount Amount of ETH to withdraw in wei
    function withdrawETH(uint256 amount) external;

    /// @notice Update minimum reputation threshold for loan requests (admin only)
    /// @dev New threshold applies to future requests only
    /// @param newMinReputation New minimum reputation value (0-1000)
    function updateMinReputation(uint16 newMinReputation) external;

    /// @notice Update cooldown period between loan requests (admin only)
    /// @param newCooldownBlocks New cooldown duration in blocks
    function updateCooldownBlocks(uint256 newCooldownBlocks) external;

    /// @notice Add a new liquidity pool for a token (admin only)
    /// @dev Requirements:
    ///   - Token must be a valid ERC20 contract
    ///   - Pool must not already exist for this token
    ///   - minLoanAmount must be <= maxLoanAmount
    /// @param token ERC20 token address for the new pool
    /// @param minLoanAmount Minimum loan amount in token decimals
    /// @param maxLoanAmount Maximum loan amount in token decimals
    function addLiquidityPool(
        address token,
        uint256 minLoanAmount,
        uint256 maxLoanAmount
    ) external;

    /// @notice Remove a liquidity pool (admin only)
    /// @dev Requirements:
    ///   - Pool must exist
    ///   - Pool should ideally have no active loans (check before calling)
    /// @param token ERC20 token address of the pool to remove
    function removeLiquidityPool(address token) external;

    /// @notice Update loan amount limits for a pool (admin only)
    /// @dev New limits apply to future loan requests only
    /// @param token ERC20 token address of the pool
    /// @param minLoanAmount New minimum loan amount in token decimals
    /// @param maxLoanAmount New maximum loan amount in token decimals
    function updatePoolLoanLimits(
        address token,
        uint256 minLoanAmount,
        uint256 maxLoanAmount
    ) external;

    /// @notice Update interest rate curve parameters for a specific pool (admin only)
    /// @dev New rates apply to future loans only; existing loans keep their locked rate
    /// @param token Pool token address
    /// @param baseRateBps Base rate in basis points (e.g., 200 = 2%)
    /// @param optimalUtilizationBps Optimal utilization kink point (e.g., 8000 = 80%)
    /// @param slope1Bps Slope below optimal utilization (e.g., 600 = 6%)
    /// @param slope2Bps Slope above optimal utilization (e.g., 4000 = 40%)
    /// @param protocolFeeBps Protocol fee on interest (e.g., 2500 = 25%)
    function updatePoolRateCurve(
        address token,
        uint256 baseRateBps,
        uint256 optimalUtilizationBps,
        uint256 slope1Bps,
        uint256 slope2Bps,
        uint256 protocolFeeBps
    ) external;

    /// @notice Withdraw accumulated protocol fees (admin only)
    /// @dev Fees are collected from interest payments on repaid loans
    /// @param token ERC20 token address to withdraw fees from
    /// @param amount Amount of fees to withdraw in token decimals
    function withdrawProtocolFees(address token, uint256 amount) external;

    // =============================================================
    //                    CONFIG GETTERS (Safe to expose)
    // =============================================================

    /// @notice Get the current loan counter (next loan ID will be this + 1)
    /// @return Current total number of loans created
    function loanCounter() external view returns (uint256);

    /// @notice Get current minimum reputation threshold
    /// @return Minimum reputation score required for loan requests (0-1000)
    function minReputation() external view returns (uint16);

    /// @notice Get current cooldown period between loan requests
    /// @return Cooldown duration in blocks
    function cooldownBlocks() external view returns (uint256);

    /// @notice Get the default token address used for new pools
    /// @return Default token address
    function defaultToken() external view returns (address);

    // =============================================================
    //                   CONSTANT / CONFIG GETTERS
    // =============================================================

    /// @notice Get configured block time for the chain
    /// @dev Used for interest calculations: blocksPerYear = 365.25 days / BLOCK_TIME_SECONDS
    /// @return Block time in seconds (e.g., 12 for Ethereum mainnet)
    function BLOCK_TIME_SECONDS() external view returns (uint256);

    /// @notice Get minimum allowed loan duration
    /// @dev Loan requests with shorter durations will revert
    /// @return Minimum duration in blocks
    function MIN_LOAN_DURATION_BLOCKS() external view returns (uint256);

    /// @notice Get maximum allowed loan duration
    /// @dev Loan requests with longer durations will revert
    /// @return Maximum duration in blocks
    function MAX_LOAN_DURATION_BLOCKS() external view returns (uint256);

    /// @notice Get maximum blocks for interest calculation
    /// @dev Prevents runaway interest accrual on abandoned loans
    /// @return Maximum blocks to use in interest calculation
    function MAX_BLOCKS_FOR_INTEREST() external view returns (uint256);

    /// @notice Get maximum pending loan requests per user
    /// @dev Prevents spam; user must wait for resolution before new requests
    /// @return Maximum number of concurrent pending loans
    function MAX_PENDING_LOANS_PER_USER() external view returns (uint256);

    /// @notice Get expiry period for approved loans
    /// @dev Approved loans must be borrowed within this period or expire
    /// @return Expiry duration in blocks after approval
    function APPROVED_LOAN_EXPIRY_BLOCKS() external view returns (uint256);

    // =============================================================
    //                INTEREST RATE CONSTANTS
    // =============================================================

    /// @notice Maximum borrower rate in basis points (50% = 5000)
    /// @return Maximum annual borrow rate in basis points
    function MAX_BORROWER_RATE() external view returns (uint256);

    /// @notice Minimum borrower rate in basis points (5% = 500)
    /// @return Minimum annual borrow rate in basis points
    function MIN_BORROWER_RATE() external view returns (uint256);
}

contracts/libraries/UnllooStatusArray.so.content:
// SPDX-License-Identifier: BUSL-1.1
pragma solidity ^0.8.24;

import "../IUnlloo.sol";
import "../errors/UnllooErrors.sol";

/**
 * @title UnllooStatusArray
 * @notice Library for managing loan status arrays with O(1) operations
 * @dev Extracted for code organization (internal libraries are inlined by the compiler)
 */
library UnllooStatusArray {
    /**
     * @notice Add loan ID to status array and index mapping
     * @param self Storage reference to the status array
     * @param indexMap Storage reference to the index mapping
     * @param loanId Loan ID to add
     * @param status Loan status
     */
    function add(
        uint256[] storage self,
        mapping(uint256 => uint256) storage indexMap,
        uint256 loanId,
        IUnlloo.LoanStatus status
    ) internal {
        uint256 existingIndex = indexMap[loanId];

        if (existingIndex < self.length && self[existingIndex] == loanId) {
            revert UnllooErrors.LoanAlreadyInStatus(loanId, uint8(status));
        }

        self.push(loanId);
        indexMap[loanId] = self.length - 1;
    }

    /**
     * @notice Remove loan ID from status array in O(1)
     * @param self Storage reference to the status array
     * @param indexMap Storage reference to the index mapping
     * @param loanId Loan ID to remove
     */
    function remove(
        uint256[] storage self,
        mapping(uint256 => uint256) storage indexMap,
        uint256 loanId,
        IUnlloo.LoanStatus
    ) internal {
        if (self.length == 0) {
            revert UnllooErrors.LoanNotFound(loanId);
        }

        uint256 index = indexMap[loanId];

        if (index >= self.length) {
            revert UnllooErrors.LoanNotFound(loanId);
        }

        if (self[index] != loanId) {
            revert UnllooErrors.LoanNotFound(loanId);
        }

        uint256 lastIndex = self.length - 1;

        if (index != lastIndex) {
            uint256 lastLoanId = self[lastIndex];
            self[index] = lastLoanId;
            indexMap[lastLoanId] = index;
        }

        self.pop();
        delete indexMap[loanId];
    }
}

contracts/Unlloo.sol.content:
// SPDX-License-Identifier: BUSL-1.1
pragma solidity ^0.8.24;

import "@openzeppelin/contracts-upgradeable/access/OwnableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/utils/PausableUpgradeable.sol";
import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";
import "./utils/ReentrancyGuardUpgradeable.sol";

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/IERC20Metadata.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

import "./IUnlloo.sol";
import "./libraries/UnllooStatusArray.sol";
import "./errors/UnllooErrors.sol";

/**
 * @title Unlloo
 * @notice Decentralized lending protocol with reputation-based loan requests
 * @dev Upgradeable contract using proxy pattern
 *
 * Production changes:
 * - Fixes critical repay accounting bug (no double-subtraction of repaid amounts)
 * - Adds fair lender yield distribution via supply index (interest paid only)
 * - Protocol fees are segregated; do not block LP principal withdrawals
 * - Interest continues accruing after due date
 * - Owner-only expiry for Approved requests
 * - Optional public "mark overdue" for correct status transitions
 * - Strict ERC20 transfers (reverts on fee-on-transfer style behavior)
 */
contract Unlloo is
    IUnlloo,
    Initializable,
    OwnableUpgradeable,
    ReentrancyGuardUpgradeable,
    PausableUpgradeable
{
    using SafeERC20 for IERC20;

    // ============ Constants ============
    uint256 public constant MAX_BLOCKS_FOR_INTEREST = 10_000_000;
    uint256 public constant MAX_PENDING_LOANS_PER_USER = 1;

    uint256 public constant MAX_BORROWER_RATE = 5000; // 50% rate cap
    uint256 public constant MIN_BORROWER_RATE = 900;  // 5% rate floor

    // Default rate curve parameters (used when adding new pools)
    uint256 private constant DEFAULT_BASE_RATE_BPS = 1200;              // 12% base rate
    uint256 private constant DEFAULT_OPTIMAL_UTILIZATION_BPS = 8000;   // 80% optimal utilization
    uint256 private constant DEFAULT_SLOPE1_BPS = 600;                 // 6% slope before optimal
    uint256 private constant DEFAULT_SLOPE2_BPS = 4000;                // 40% slope after optimal
    uint256 private constant DEFAULT_PROTOCOL_FEE_BPS = 2500;          // 25% protocol fee

    uint256 private constant INDEX_SCALE = 1e18; // For supply index calculations

    // ============ State Variables ============
    uint256 public override loanCounter;
    mapping(uint256 => Loan) public loans;
    mapping(address => uint256[]) private _borrowerLoans;

    mapping(LoanStatus => uint256[]) private _loansByStatus;
    mapping(LoanStatus => mapping(uint256 => uint256)) private _loanStatusIndex;

    mapping(address => LiquidityPool) public pools;
    mapping(address => mapping(address => LenderPosition)) public lenderPositions;
    mapping(address => uint256) public lastRequestBlock;
    mapping(address => uint256) public protocolFees;

    mapping(address => uint256) public activeLenderCount;

    mapping(address => uint256) public minLoanAmountPerPool;
    mapping(address => uint256) public maxLoanAmountPerPool;

    uint16 public override minReputation;
    uint256 public override cooldownBlocks;

    uint256 public override BLOCK_TIME_SECONDS;
    uint256 public override MIN_LOAN_DURATION_BLOCKS;
    uint256 public override MAX_LOAN_DURATION_BLOCKS;
    uint256 public override APPROVED_LOAN_EXPIRY_BLOCKS;

    address public override defaultToken;

    // ============ Simple Interest State ============
    mapping(uint256 => uint256) public loanInitialPrincipal;

    /// @notice One active loan per borrower; 0 if none
    mapping(address => uint256) private _activeLoanByBorrower;

    /// @notice Number of loans in UnpaidDebt status per borrower
    mapping(address => uint256) public unpaidDebtLoanCount;
    /// @notice Number of open requests (Pending or Approved) per borrower
    mapping(address => uint256) public openRequestCount;

    // ============ Lender Yield (Supply Index) ============
    mapping(address => uint256) public poolSupplyIndex; // token => index (1e18)
    mapping(address => uint256) public poolUndistributedInterest; // rounding dust bucket
    mapping(address => mapping(address => uint256)) public lenderSupplyIndex; // lender => token => index snapshot
    mapping(address => mapping(address => uint256)) public lenderAccruedInterest; // lender => token => accrued

    // ============ Per-pool active loan counters (avoid O(n) scans) ============
    mapping(address => uint256) public activeLoansPerPool;
    mapping(address => uint256) public unpaidDebtLoansPerPool;

    // ============ Per-pool Interest Rate Parameters ============
    mapping(address => RateCurveParams) private _poolRateCurve;

    uint256[35] private __gap;

    // ============ Constructor ============
    /// @custom:oz-upgrades-unsafe-allow constructor
    constructor() {
        _disableInitializers();
    }

    // ============ Modifiers ============
    modifier loanExists(uint256 loanId) {
        if (loans[loanId].borrower == address(0)) revert UnllooErrors.LoanNotFound(loanId);
        _;
    }

    modifier onlyBorrower(uint256 loanId) {
        if (msg.sender != loans[loanId].borrower) revert UnllooErrors.NotBorrower(msg.sender, loans[loanId].borrower);
        _;
    }

    modifier validPool(address token) {
        if (token == address(0) || pools[token].token == address(0)) revert UnllooErrors.InvalidPool(token);
        _;
    }

    // ============ Initializer ============
    function initialize(
        address _defaultToken,
        uint256 _blockTimeSeconds,
        address initialOwner,
        uint256 _defaultMinLoanAmount,
        uint256 _defaultMaxLoanAmount
    ) public initializer {
        if (initialOwner == address(0)) revert UnllooErrors.InvalidOwner(initialOwner);
        if (_defaultToken == address(0)) revert UnllooErrors.InvalidDefaultToken(address(0));
        if (_blockTimeSeconds == 0 || _blockTimeSeconds > 86400) revert UnllooErrors.InvalidBlockTime(_blockTimeSeconds);

        if (_defaultMinLoanAmount == 0 || _defaultMaxLoanAmount == 0) {
            revert UnllooErrors.InvalidPoolLoanLimits(_defaultMinLoanAmount, _defaultMaxLoanAmount);
        }
        if (_defaultMinLoanAmount >= _defaultMaxLoanAmount) {
            revert UnllooErrors.InvalidPoolLoanLimits(_defaultMinLoanAmount, _defaultMaxLoanAmount);
        }

        __Ownable_init(initialOwner);
        __Pausable_init();
        __ReentrancyGuard_init();

        defaultToken = _defaultToken;
        BLOCK_TIME_SECONDS = _blockTimeSeconds;

        _validateTokenDecimals(_defaultToken);

        pools[_defaultToken] = LiquidityPool({ token: _defaultToken, totalLiquidity: 0, borrowedAmount: 0 });
        minLoanAmountPerPool[_defaultToken] = _defaultMinLoanAmount;
        maxLoanAmountPerPool[_defaultToken] = _defaultMaxLoanAmount;

        // supply index starts at 1e18
        poolSupplyIndex[_defaultToken] = 1e18;

        // Set default rate curve for default pool
        _poolRateCurve[_defaultToken] = RateCurveParams({
            baseRateBps: DEFAULT_BASE_RATE_BPS,
            optimalUtilizationBps: DEFAULT_OPTIMAL_UTILIZATION_BPS,
            slope1Bps: DEFAULT_SLOPE1_BPS,
            slope2Bps: DEFAULT_SLOPE2_BPS,
            protocolFeeBps: DEFAULT_PROTOCOL_FEE_BPS
        });

        minReputation = 200;

        // Calculate blocks per day (multiply first, divide last to avoid precision loss)
        uint256 secondsPerDay = 24 * 60 * 60;
        uint256 blocksPerDay = secondsPerDay / BLOCK_TIME_SECONDS;
        if (blocksPerDay == 0) revert UnllooErrors.InvalidBlockTime(_blockTimeSeconds);

        // Calculate duration constants (multiply first, divide last)
        MIN_LOAN_DURATION_BLOCKS = blocksPerDay;
        MAX_LOAN_DURATION_BLOCKS = (secondsPerDay * 60) / BLOCK_TIME_SECONDS; // 60 days
        APPROVED_LOAN_EXPIRY_BLOCKS = (secondsPerDay * 30) / BLOCK_TIME_SECONDS; // 30 days
        cooldownBlocks = blocksPerDay;
    }

    // ============ Loan Request Functions ============
    function submitLoanRequest(
        uint16 walletReputation,
        address token,
        uint256 loanAmount,
        uint256 loanDurationBlocks
    ) external override whenNotPaused nonReentrant returns (uint256 loanId) {
        if (walletReputation < minReputation || walletReputation > 1000) {
            revert UnllooErrors.InvalidReputation(walletReputation, minReputation);
        }
        if (token == address(0) || pools[token].token == address(0)) revert UnllooErrors.InvalidPool(token);

        (uint256 minLoanAmountToken, uint256 maxLoanAmountToken) = _getLoanLimits(token);

        if (loanAmount < minLoanAmountToken || loanAmount > maxLoanAmountToken) {
            revert UnllooErrors.InvalidAmount(loanAmount, minLoanAmountToken, maxLoanAmountToken);
        }
        if (loanDurationBlocks < MIN_LOAN_DURATION_BLOCKS || loanDurationBlocks > MAX_LOAN_DURATION_BLOCKS) {
            revert UnllooErrors.InvalidDuration(loanDurationBlocks, MIN_LOAN_DURATION_BLOCKS, MAX_LOAN_DURATION_BLOCKS);
        }
        if (hasUnpaidDebt(msg.sender)) revert UnllooErrors.HasUnpaidDebt(msg.sender);
        if (openRequestCount[msg.sender] >= MAX_PENDING_LOANS_PER_USER) revert UnllooErrors.ExceedsMaxPendingLoans(msg.sender);
        if (_activeLoanByBorrower[msg.sender] != 0) revert UnllooErrors.HasActiveLoan(msg.sender);

        if (lastRequestBlock[msg.sender] > 0) {
            uint256 cooldownEnd = lastRequestBlock[msg.sender] + cooldownBlocks;
            if (block.number < cooldownEnd) revert UnllooErrors.CooldownNotExpired(msg.sender, cooldownEnd);
        }

        loanId = ++loanCounter;

        loans[loanId] = Loan({
            loanId: loanId,
            borrower: msg.sender,
            status: LoanStatus.Pending,
            walletReputation: walletReputation,
            loanAmount: loanAmount,
            loanDurationBlocks: loanDurationBlocks,
            chainId: block.chainid,
            requestBlock: block.number,
            approvalBlock: 0,
            token: token,
            principal: 0,
            amountRepaid: 0, // informational only; not used for debt math
            startBlock: 0,
            deadlineBlock: 0,
            protocolFee: 0,
            interestAccrued: 0,
            borrowRateBps: 0,
            lastAccrualBlock: 0
        });

        _borrowerLoans[msg.sender].push(loanId);
        UnllooStatusArray.add(_loansByStatus[LoanStatus.Pending], _loanStatusIndex[LoanStatus.Pending], loanId, LoanStatus.Pending);

        openRequestCount[msg.sender] += 1;
        lastRequestBlock[msg.sender] = block.number;

        emit LoanRequestSubmitted(loanId, msg.sender, walletReputation, loanAmount, loanDurationBlocks, block.number);
    }

    function approveLoanRequest(uint256 loanId)
        external
        override
        onlyOwner
        nonReentrant
        loanExists(loanId)
    {
        Loan storage loan = loans[loanId];

        if (loan.status != LoanStatus.Pending) revert UnllooErrors.InvalidLoanStatus(uint8(loan.status), uint8(LoanStatus.Pending));
        if (hasUnpaidDebt(loan.borrower)) revert UnllooErrors.HasUnpaidDebt(loan.borrower);
        if (_activeLoanByBorrower[loan.borrower] != 0) revert UnllooErrors.HasActiveLoan(loan.borrower);

        loan.status = LoanStatus.Approved;
        loan.approvalBlock = block.number;

        UnllooStatusArray.remove(_loansByStatus[LoanStatus.Pending], _loanStatusIndex[LoanStatus.Pending], loanId, LoanStatus.Pending);
        UnllooStatusArray.add(_loansByStatus[LoanStatus.Approved], _loanStatusIndex[LoanStatus.Approved], loanId, LoanStatus.Approved);

        emit LoanRequestApproved(loanId, loan.borrower, block.number);
    }

    function rejectLoanRequest(uint256 loanId)
        external
        override
        onlyOwner
        nonReentrant
        loanExists(loanId)
    {
        Loan storage loan = loans[loanId];
        if (loan.status != LoanStatus.Pending) revert UnllooErrors.InvalidLoanStatus(uint8(loan.status), uint8(LoanStatus.Pending));

        loan.status = LoanStatus.Rejected;

        UnllooStatusArray.remove(_loansByStatus[LoanStatus.Pending], _loanStatusIndex[LoanStatus.Pending], loanId, LoanStatus.Pending);
        UnllooStatusArray.add(_loansByStatus[LoanStatus.Rejected], _loanStatusIndex[LoanStatus.Rejected], loanId, LoanStatus.Rejected);

        if (openRequestCount[loan.borrower] > 0) openRequestCount[loan.borrower] -= 1;

        emit LoanRequestRejected(loanId, loan.borrower, block.number);
    }

    /**
     * @notice Owner-only expiry for Approved requests (prevents permanent openRequestCount lock)
     */
    function expireApprovedLoan(uint256 loanId)
        external
        onlyOwner
        nonReentrant
        loanExists(loanId)
    {
        Loan storage loan = loans[loanId];
        if (loan.status != LoanStatus.Approved) revert UnllooErrors.InvalidLoanStatus(uint8(loan.status), uint8(LoanStatus.Approved));

        uint256 expiryBlock = loan.approvalBlock + APPROVED_LOAN_EXPIRY_BLOCKS;
        if (block.number <= expiryBlock) {
            revert UnllooErrors.ApprovedLoanExpired(loanId, loan.approvalBlock, expiryBlock);
        }

        loan.status = LoanStatus.Rejected;

        UnllooStatusArray.remove(_loansByStatus[LoanStatus.Approved], _loanStatusIndex[LoanStatus.Approved], loanId, LoanStatus.Approved);
        UnllooStatusArray.add(_loansByStatus[LoanStatus.Rejected], _loanStatusIndex[LoanStatus.Rejected], loanId, LoanStatus.Rejected);

        if (openRequestCount[loan.borrower] > 0) openRequestCount[loan.borrower] -= 1;

        emit LoanRequestRejected(loanId, loan.borrower, block.number);
    }

    // ============ Borrowing Functions ============
    function borrow(
        uint256 loanId,
        uint256 tokenAmount
    ) external override whenNotPaused nonReentrant loanExists(loanId) onlyBorrower(loanId) {
        Loan storage loan = loans[loanId];

        if (loan.status != LoanStatus.Approved) revert UnllooErrors.InvalidLoanStatus(uint8(loan.status), uint8(LoanStatus.Approved));
        if (tokenAmount == 0) revert UnllooErrors.InvalidAmount(tokenAmount, 1, type(uint256).max);

        uint256 expiryBlock = loan.approvalBlock + APPROVED_LOAN_EXPIRY_BLOCKS;
        if (block.number > expiryBlock) revert UnllooErrors.ApprovedLoanExpired(loanId, loan.approvalBlock, expiryBlock);

        if (_activeLoanByBorrower[msg.sender] != 0) revert UnllooErrors.HasActiveLoan(msg.sender);

        address token = loan.token;
        if (token == address(0) || pools[token].token == address(0)) revert UnllooErrors.InvalidPool(token);

        uint256 maxTokenAmount = getApprovedLoanAmount(loanId);
        if (tokenAmount > maxTokenAmount) revert UnllooErrors.InvalidAmount(tokenAmount, 1, maxTokenAmount);

        LiquidityPool storage pool = pools[token];

        if (pool.borrowedAmount > pool.totalLiquidity) revert UnllooErrors.InsufficientLiquidity(tokenAmount, 0);
        uint256 freeLiquidity = pool.totalLiquidity - pool.borrowedAmount;
        if (tokenAmount > freeLiquidity) revert UnllooErrors.InsufficientLiquidity(tokenAmount, freeLiquidity);

        if (loan.loanDurationBlocks > MAX_BLOCKS_FOR_INTEREST) {
            revert UnllooErrors.InvalidDuration(loan.loanDurationBlocks, 1, MAX_BLOCKS_FOR_INTEREST);
        }

        // Calculate fixed borrow rate based on current utilization
        uint256 borrowRateBps = _calculateBorrowRate(token);

        loanInitialPrincipal[loanId] = tokenAmount;

        loan.status = LoanStatus.Active;
        loan.principal = tokenAmount;
        loan.amountRepaid = 0;
        loan.startBlock = block.number;
        loan.deadlineBlock = block.number + loan.loanDurationBlocks;
        loan.protocolFee = 0;
        loan.interestAccrued = 0;
        loan.borrowRateBps = borrowRateBps; // Fixed rate for loan lifetime
        loan.lastAccrualBlock = block.number; // Initialize accrual tracking

        UnllooStatusArray.remove(_loansByStatus[LoanStatus.Approved], _loanStatusIndex[LoanStatus.Approved], loanId, LoanStatus.Approved);
        UnllooStatusArray.add(_loansByStatus[LoanStatus.Active], _loanStatusIndex[LoanStatus.Active], loanId, LoanStatus.Active);

        _activeLoanByBorrower[loan.borrower] = loanId;

        if (openRequestCount[loan.borrower] > 0) openRequestCount[loan.borrower] -= 1;

        pool.borrowedAmount += tokenAmount;
        activeLoansPerPool[token] += 1;

        _safeTransferExact(token, msg.sender, tokenAmount);

        // Calculate expected interest using simple interest for event
        // Formula: I = P * r * t where t = blocksElapsed / blocksPerYear
        // Multiply first, divide last to avoid precision loss:
        // expectedInterest = (tokenAmount * borrowRateBps * loanDurationBlocks * BLOCK_TIME_SECONDS) / (10000 * SECONDS_PER_YEAR)
        uint256 secondsPerYear = 365 * 24 * 60 * 60;
        uint256 expectedInterest = (tokenAmount * borrowRateBps * loan.loanDurationBlocks * BLOCK_TIME_SECONDS) / (10000 * secondsPerYear);
        uint256 expectedTotalOwed = tokenAmount + expectedInterest;

        emit LoanBorrowed(loanId, msg.sender, token, tokenAmount, expectedTotalOwed, block.number);
    }

    function getApprovedLoanAmount(uint256 loanId)
        public
        view
        override
        loanExists(loanId)
        returns (uint256 approvedAmount)
    {
        Loan memory loan = loans[loanId];
        if (loan.status != LoanStatus.Approved && loan.status != LoanStatus.Pending) return 0;
        return loan.loanAmount;
    }

    // ============ Repayment / Overdue ============
    /**
     * @notice Mark an overdue Active loan as UnpaidDebt in storage
     * @dev This function syncs storage state with the virtual status projection from getLoan().
     *      Anyone can call this to ensure storage reflects the actual overdue status.
     *      
     *      **Why this exists:**
     *      - getLoan() performs virtual status projection for UI convenience
     *      - Storage may lag behind until this function is called
     *      - State-changing functions (like repay()) automatically transition overdue loans
     *      - This function allows explicit synchronization of storage with projection
     *      
     *      **Effects:**
     *      - Updates loan.status to UnpaidDebt in storage
     *      - Updates status arrays and counters
     *      - Emits LoanMovedToUnpaidDebt event
     *      
     *      @param loanId The ID of the overdue loan to mark
     */
    function markLoanOverdue(uint256 loanId)
        external
        nonReentrant
        loanExists(loanId)
    {
        Loan storage loan = loans[loanId];
        if (loan.status != LoanStatus.Active) revert UnllooErrors.InvalidLoanStatus(uint8(loan.status), uint8(LoanStatus.Active));
        // Sentinel check: loan not yet started (startBlock == 0) or invalid duration
        if (loan.startBlock == 0 || loan.loanDurationBlocks == 0) revert UnllooErrors.InvalidLoanStatus(uint8(loan.status), uint8(LoanStatus.Active));

        uint256 deadline = loan.deadlineBlock != 0 ? loan.deadlineBlock : (loan.startBlock + loan.loanDurationBlocks);
        if (block.number < deadline) revert UnllooErrors.InvalidDuration(block.number, deadline, type(uint256).max);

        _transitionToUnpaidDebt(loanId, loan, deadline);
    }

    function repay(
        uint256 loanId,
        uint256 amount
    ) external override nonReentrant loanExists(loanId) onlyBorrower(loanId) {
        Loan storage loan = loans[loanId];

        _validateRepaymentConditions(loan, amount);

        // Accrue simple interest before any operations
        _accrueLoanInterest(loanId);

        // If overdue, transition to UnpaidDebt in storage
        _checkAndTransitionOverdue(loanId, loan);

        // Calculate payment amounts
        (uint256 payAmount, uint256 interestPayment, uint256 principalPayment) = 
            _calculateRepaymentSplit(loan, amount);

        // Pull funds (strict: disallow fee-on-transfer behavior)
        _safeTransferFromExact(loan.token, msg.sender, address(this), payAmount);

        // Process interest payment with protocol fees
        if (interestPayment > 0) {
            _processInterestPayment(loan, interestPayment);
        }

        // Record informational repayment (NOT used for debt math)
        loan.amountRepaid += payAmount;

        // Apply principal payment
        if (principalPayment > 0) {
            _applyPrincipalPayment(loan, principalPayment);
        }

        // Check if loan is fully repaid and finalize
        uint256 newTotalDue = _checkAndFinalizeRepayment(loanId, loan);

        emit LoanRepaid(loanId, msg.sender, loan.token, payAmount, newTotalDue, block.number);
    }

    /// @dev Validates conditions required for repayment
    function _validateRepaymentConditions(Loan storage loan, uint256 amount) internal view {
        if (loan.status != LoanStatus.Active && loan.status != LoanStatus.UnpaidDebt) {
            revert UnllooErrors.InvalidLoanStatus(uint8(loan.status), uint8(LoanStatus.Active));
        }
        if (amount == 0) revert UnllooErrors.InvalidAmount(amount, 1, type(uint256).max);
        if (loan.token == address(0) || pools[loan.token].token == address(0)) {
            revert UnllooErrors.InvalidPool(loan.token);
        }
        // Sentinel check: loan not yet started (startBlock == 0)
        if (loan.startBlock == 0) {
            revert UnllooErrors.InvalidLoanStatus(uint8(loan.status), uint8(LoanStatus.Active));
        }
    }

    /// @dev Checks if loan is overdue and transitions to UnpaidDebt in storage if necessary
    /// @notice This is called automatically in state-changing functions (e.g., repay())
    ///         to ensure storage state matches the virtual projection from getLoan()
    /// @param loanId The loan ID to check
    /// @param loan Storage reference to the loan
    function _checkAndTransitionOverdue(uint256 loanId, Loan storage loan) internal {
        if (loan.status != LoanStatus.Active) return;

        uint256 deadline = loan.deadlineBlock != 0 
            ? loan.deadlineBlock 
            : (loan.startBlock + loan.loanDurationBlocks);

        if (block.number >= deadline) {
            _transitionToUnpaidDebt(loanId, loan, deadline);
        }
    }

    /// @dev Calculates how to split the repayment between interest and principal
    function _calculateRepaymentSplit(
        Loan storage loan, 
        uint256 amount
    ) internal view returns (uint256 payAmount, uint256 interestPayment, uint256 principalPayment) {
        uint256 interestDue = loan.interestAccrued;
        uint256 principalOutstanding = loan.principal;
        uint256 totalDue = principalOutstanding + interestDue;

        if (totalDue == 0) revert UnllooErrors.InvalidAmount(amount, 1, 0);

        // Cap payment at total due to prevent overpayment
        payAmount = amount > totalDue ? totalDue : amount;

        // Interest first, then principal
        interestPayment = payAmount > interestDue ? interestDue : payAmount;
        principalPayment = payAmount - interestPayment;
    }

    /// @dev Processes interest payment including protocol fees and lender distribution
    /// @notice Updates lastAccrualBlock only when interest is fully settled
    ///         This ensures the accrual baseline persists across partial interest payments
    function _processInterestPayment(Loan storage loan, uint256 interestPayment) internal {
        uint256 poolProtocolFeeBps = _poolRateCurve[loan.token].protocolFeeBps;
        uint256 protocolFeeForPayment = (interestPayment * poolProtocolFeeBps) / 10000;
        uint256 lenderInterest = interestPayment - protocolFeeForPayment;

        // Update protocol revenue
        protocolFees[loan.token] += protocolFeeForPayment;
        loan.protocolFee += protocolFeeForPayment;

        // Reduce accrued interest
        loan.interestAccrued -= interestPayment;

        // Distribute lender interest via supply index
        if (lenderInterest > 0) {
            _distributeInterestToLenders(loan.token, lenderInterest);
        }

        // Only update lastAccrualBlock when interest is fully settled
        // This ensures the accrual baseline is not reset on partial interest payments
        // and prevents micro-repayments from reducing interest growth
        if (loan.interestAccrued == 0) {
            loan.lastAccrualBlock = block.number;
        }
    }

    /// @dev Applies principal payment and updates pool borrowed amount
    /// @notice Does NOT reset lastAccrualBlock - interest accrual baseline is separate from principal
    ///         This ensures micro-repayments don't reduce interest growth and borrowers pay full time-based interest
    function _applyPrincipalPayment(Loan storage loan, uint256 principalPayment) internal {
        // Cap at actual principal to prevent underflow
        if (principalPayment > loan.principal) {
            principalPayment = loan.principal;
        }

        loan.principal -= principalPayment;

        // Update pool borrowedAmount
        LiquidityPool storage pool = pools[loan.token];
        if (principalPayment > pool.borrowedAmount) {
            pool.borrowedAmount = 0;
        } else {
            pool.borrowedAmount -= principalPayment;
        }

        // DO NOT reset lastAccrualBlock here - it should only update when interest is fully settled
        // This ensures continuous interest accrual regardless of principal payments
    }

    /// @dev Checks if loan is fully repaid and finalizes if so
    /// @return newTotalDue The remaining total due after repayment
    function _checkAndFinalizeRepayment(uint256 loanId, Loan storage loan) internal returns (uint256 newTotalDue) {
        uint256 newAccrued = _getAccruedInterest(loanId);
        newTotalDue = loan.principal + newAccrued;

        // NOTE: We intentionally do NOT forgive principal "dust".
        // Forgiving principal without receiving tokens breaks conservation and can cause LP withdrawals
        // to revert (NotEnoughCash). Borrowers must repay full principal.
        // Sentinel check: loan fully repaid (principal and all interest cleared)
        if (loan.principal == 0 && newTotalDue == 0) {
            _finalizeRepaid(loanId, loan);
        }
    }

    // ============ Liquidity Pool Functions ============
    function depositLiquidity(address token, uint256 amount)
        external
        override
        whenNotPaused
        nonReentrant
        validPool(token)
    {
        if (amount == 0) revert UnllooErrors.InvalidAmount(amount, 1, type(uint256).max);

        uint256 allowance = IERC20(token).allowance(msg.sender, address(this));
        if (allowance < amount) revert UnllooErrors.InsufficientAllowance(amount, allowance);

        _distributePendingInterest(token);
        _updateLenderAccrual(msg.sender, token);

        _safeTransferFromExact(token, msg.sender, address(this), amount);

        LenderPosition storage position = lenderPositions[msg.sender][token];
        bool isNewLender = position.lender == address(0);

        if (isNewLender) {
            position.lender = msg.sender;
            position.token = token;
            position.depositBlock = block.number;
            position.lastWithdrawBlock = block.number;
            activeLenderCount[token] += 1;
        }

        position.depositedAmount += amount;
        pools[token].totalLiquidity += amount;

        emit LiquidityDeposited(msg.sender, token, amount, block.number);
    }

    function withdrawLiquidity(address token, uint256 amount)
        external
        override
        whenNotPaused
        nonReentrant
        validPool(token)
    {
        if (amount == 0) revert UnllooErrors.InvalidAmount(amount, 1, type(uint256).max);

        _distributePendingInterest(token);
        _updateLenderAccrual(msg.sender, token);

        LenderPosition storage position = lenderPositions[msg.sender][token];
        if (position.lender == address(0) || position.depositedAmount == 0) revert UnllooErrors.InvalidAmount(amount, 1, 0);
        if (amount > position.depositedAmount) revert UnllooErrors.InvalidAmount(amount, 1, position.depositedAmount);

        LiquidityPool storage pool = pools[token];
        if (pool.borrowedAmount > pool.totalLiquidity) revert UnllooErrors.InsufficientLiquidity(amount, 0);

        uint256 freeLiquidity = pool.totalLiquidity - pool.borrowedAmount;
        if (amount > freeLiquidity) revert UnllooErrors.InsufficientLiquidity(amount, freeLiquidity);

        uint256 accrued = lenderAccruedInterest[msg.sender][token];

        uint256 interestToPay;
        if (amount == position.depositedAmount) {
            // Full withdrawal: pay all interest
            interestToPay = accrued;
        } else {
            // Partial: pay pro-rata
            interestToPay = (accrued * amount) / position.depositedAmount;
        }

        // Update storage before external call
        position.depositedAmount -= amount;
        position.lastWithdrawBlock = block.number;
        pool.totalLiquidity -= amount;

        if (interestToPay > 0) {
            lenderAccruedInterest[msg.sender][token] = accrued - interestToPay;
        }

        if (position.depositedAmount == 0) {
            delete lenderPositions[msg.sender][token];
            delete lenderSupplyIndex[msg.sender][token];
            delete lenderAccruedInterest[msg.sender][token];
            activeLenderCount[token] -= 1;
        }

        uint256 totalPayout = amount + interestToPay;

        // Ensure we do not spend reserved protocol fees
        uint256 balance = IERC20(token).balanceOf(address(this));
        if (balance < totalPayout) revert UnllooErrors.NotEnoughCash(totalPayout, balance);
        if (balance - totalPayout < protocolFees[token]) revert UnllooErrors.NotEnoughCash(totalPayout, balance - protocolFees[token]);

        _safeTransferExact(token, msg.sender, totalPayout);

        emit LiquidityWithdrawn(msg.sender, token, amount, interestToPay, totalPayout, block.number);
    }

    function getLenderPosition(address lender, address token)
        external
        view
        override
        returns (uint256 depositedAmount, uint256 accruedInterest, uint256 totalWithdrawable)
    {
        LenderPosition memory position = lenderPositions[lender][token];
        if (position.lender == address(0) || position.depositedAmount == 0) return (0, 0, 0);

        depositedAmount = position.depositedAmount;

        uint256 idx = poolSupplyIndex[token];
        uint256 und = poolUndistributedInterest[token];
        uint256 tl = pools[token].totalLiquidity;
        if (und > 0 && tl > 0) {
            idx += (und * INDEX_SCALE) / tl;
        }

        uint256 lenderIdx = lenderSupplyIndex[lender][token];
        uint256 pending = 0;
        if (idx > lenderIdx) {
            pending = (depositedAmount * (idx - lenderIdx)) / INDEX_SCALE;
        }

        accruedInterest = lenderAccruedInterest[lender][token] + pending;
        totalWithdrawable = depositedAmount + accruedInterest;
    }

    // ============ View Functions ============
    function _interestDue(uint256 loanId) internal view returns (uint256) {
        return _getAccruedInterest(loanId);
    }

    function _totalOwed(uint256 loanId) internal view returns (uint256) {
        return loans[loanId].principal + _interestDue(loanId);
    }

    /// @notice Get loan information with virtual status projection
    /// @dev **IMPORTANT: This function performs VIRTUAL STATUS PROJECTION**
    ///      The returned loan status may differ from actual storage state.
    ///      
    ///      For Active loans past their deadline, this function returns UnpaidDebt
    ///      even if storage still shows Active. This is for UI convenience.
    ///      
    ///      **Storage State Transitions:**
    ///      - Storage transitions to UnpaidDebt occur via:
    ///        1. Explicit call to `markLoanOverdue(loanId)` (anyone can call)
    ///        2. Automatic transition in state-changing functions like `repay()`
    ///      
    ///      **Frontend/Indexer Considerations:**
    ///      - Frontends should use this function for display purposes
    ///      - Indexers should track both projected status (from getLoan) and actual storage
    ///      - State-changing operations use actual storage status, not projected status
    ///      - To sync storage with projection, call `markLoanOverdue()` before state changes
    ///      
    ///      @param loanId The ID of the loan to retrieve
    ///      @return loan Loan struct with potentially projected status
    function getLoan(uint256 loanId)
        external
        view
        override
        returns (Loan memory loan)
    {
        loan = loans[loanId];
        if (loan.borrower == address(0)) return loan;

        // Virtual status projection: reflect overdue status for UI even if storage hasn't updated
        if (loan.status == LoanStatus.Active || loan.status == LoanStatus.UnpaidDebt) {
            uint256 deadline = loan.deadlineBlock;
            if (deadline == 0) deadline = loan.startBlock + loan.loanDurationBlocks;
            if (deadline != 0 && block.number >= deadline) {
                // Project UnpaidDebt status even if storage still shows Active
                // Storage will be updated by markLoanOverdue() or during state-changing operations
                loan.status = LoanStatus.UnpaidDebt;
                loan.deadlineBlock = deadline;
            }
        }
    }

    function getAccruedInterest(uint256 loanId)
        external
        view
        override
        loanExists(loanId)
        returns (uint256 accruedInterest)
    {
        return _interestDue(loanId);
    }

    function getTotalOwed(uint256 loanId)
        external
        view
        override
        loanExists(loanId)
        returns (uint256 totalOwed)
    {
        return _totalOwed(loanId);
    }

    function getRemainingBalance(uint256 loanId)
        external
        view
        override
        loanExists(loanId)
        returns (uint256 remainingBalance)
    {
        return _totalOwed(loanId);
    }

    function calculateBorrowRate(address token)
        external
        view
        override
        returns (uint256 rateBps)
    {
        return _calculateBorrowRate(token);
    }

    function getLoansByBorrower(address borrower)
        external
        view
        override
        returns (uint256[] memory)
    {
        return _borrowerLoans[borrower];
    }

    function getLoansByStatus(
        LoanStatus status,
        uint256 offset,
        uint256 limit
    ) external view override returns (uint256[] memory loanIds) {
        uint256[] storage statusLoans = _loansByStatus[status];
        uint256 length = statusLoans.length;

        if (offset >= length || limit == 0) return loanIds;

        uint256 end = offset + limit;
        if (end > length) end = length;

        uint256 resultLength = end - offset;
        loanIds = new uint256[](resultLength);

        for (uint256 i = offset; i < end; i++) {
            loanIds[i - offset] = statusLoans[i];
        }
    }

    function getLiquidityPool(address token)
        external
        view
        override
        returns (LiquidityPool memory pool)
    {
        pool = pools[token];
    }

    function getActiveLenderCount(address token)
        external
        view
        override
        returns (uint256 count)
    {
        return activeLenderCount[token];
    }

    function hasUnpaidDebt(address user)
        public
        view
        override
        returns (bool)
    {
        if (unpaidDebtLoanCount[user] != 0) return true;

        uint256 activeId = _activeLoanByBorrower[user];
        // Sentinel check: no active loan ID set
        if (activeId == 0) return false;

        Loan memory loan = loans[activeId];
        if (loan.status == LoanStatus.UnpaidDebt) return true;
        if (loan.status != LoanStatus.Active) return false;
        // Sentinel check: loan not yet started (startBlock == 0) or invalid duration
        if (loan.startBlock == 0 || loan.loanDurationBlocks == 0) return false;

        uint256 deadline = loan.deadlineBlock != 0 ? loan.deadlineBlock : (loan.startBlock + loan.loanDurationBlocks);
        return block.number >= deadline;
    }

    function getActiveLoanByBorrower(address borrower)
        external
        view
        override
        returns (uint256 loanId)
    {
        loanId = _activeLoanByBorrower[borrower];
        // Sentinel check: no active loan ID set
        if (loanId == 0) return 0;

        Loan memory loan = loans[loanId];
        if (loan.status != LoanStatus.Active) return 0;
        // Sentinel check: loan not yet started (startBlock == 0) or invalid duration
        if (loan.startBlock == 0 || loan.loanDurationBlocks == 0) return 0;

        uint256 deadline = loan.deadlineBlock != 0 ? loan.deadlineBlock : (loan.startBlock + loan.loanDurationBlocks);
        if (block.number >= deadline) return 0;

        return loanId;
    }

    function getProtocolFees(address token)
        external
        view
        override
        returns (uint256 balance)
    {
        return protocolFees[token];
    }

    function canSubmitRequest(address user)
        external
        view
        override
        returns (bool)
    {
        if (hasUnpaidDebt(user)) return false;
        if (_activeLoanByBorrower[user] != 0) return false;
        if (openRequestCount[user] >= MAX_PENDING_LOANS_PER_USER) return false;

        uint256 lastRequest = lastRequestBlock[user];
        if (lastRequest == 0) return true;

        return block.number >= lastRequest + cooldownBlocks;
    }

    function getCooldownEndBlock(address user)
        external
        view
        override
        returns (uint256 cooldownEndBlock)
    {
        if (user == address(0)) return type(uint256).max;

        uint256 lastRequest = lastRequestBlock[user];
        if (lastRequest == 0) return 0;

        return lastRequest + cooldownBlocks;
    }

    function borrowerLoans(address borrower)
        external
        view
        returns (uint256[] memory)
    {
        return _borrowerLoans[borrower];
    }

    function loansByStatus(LoanStatus status)
        external
        view
        returns (uint256[] memory)
    {
        return _loansByStatus[status];
    }

    // ============ Admin Functions ============
    function pause() external override onlyOwner { _pause(); }
    function unpause() external override onlyOwner { _unpause(); }

    /**
     * @dev Safer emergency withdraw: only allows withdrawing tokens NOT configured as a pool token.
     *      For pool tokens, use withdrawProtocolFees().
     */
    function emergencyWithdraw(address token, uint256 amount)
        external
        onlyOwner
        whenPaused
        nonReentrant
    {
        _validateNonZeroAddress(token);

        // Disallow emergency withdraw for active pools to prevent accidental LP fund theft.
        if (pools[token].token != address(0)) revert UnllooErrors.InvalidPool(token);

        uint256 balance = IERC20(token).balanceOf(address(this));
        _validateNonZeroAmount(amount, balance);

        _safeTransferExact(token, owner(), amount);
        emit EmergencyWithdraw(token, amount, block.number);
    }

    function withdrawETH(uint256 amount)
        external
        override
        onlyOwner
        nonReentrant
        whenNotPaused
    {
        uint256 fees = protocolFees[address(0)];
        if (amount == 0 || amount > fees) revert UnllooErrors.InvalidAmount(amount, 1, fees);

        uint256 bal = address(this).balance;
        if (amount > bal) revert UnllooErrors.InvalidAmount(amount, 1, bal);

        // Effects (state changes before external call - CEI pattern)
        protocolFees[address(0)] = fees - amount;
        address recipient = owner();

        // Emit before interaction (strict CEI)
        emit ETHWithdrawn(recipient, amount, block.number);

        // Interaction: low-level call with explicit error handling
        // Using call{value:}("") is the recommended pattern for ETH transfers
        // as it forwards all available gas and handles contract recipients
        (bool success, ) = payable(recipient).call{ value: amount }("");
        require(success, "ETH_TRANSFER_FAILED");
    }

    function updateMinReputation(uint16 newMinReputation)
        external
        override
        onlyOwner
    {
        if (newMinReputation > 1000) revert UnllooErrors.InvalidReputation(newMinReputation, 0);
        if (newMinReputation == minReputation) revert UnllooErrors.InvalidReputation(newMinReputation, minReputation);

        uint16 oldMinReputation = minReputation;
        minReputation = newMinReputation;

        emit MinReputationUpdated(oldMinReputation, newMinReputation, block.number);
    }


    function updateCooldownBlocks(uint256 newCooldownBlocks)
        external
        override
        onlyOwner
    {
        // Calculate min/max cooldown (multiply first, divide last to avoid precision loss)
        uint256 secondsPerDay = 24 * 60 * 60;
        uint256 minCooldown = secondsPerDay / BLOCK_TIME_SECONDS;
        if (minCooldown == 0) revert UnllooErrors.InvalidBlockTime(BLOCK_TIME_SECONDS);

        // maxCooldown = 30 days worth of blocks
        uint256 maxCooldown = (secondsPerDay * 30) / BLOCK_TIME_SECONDS;

        if (newCooldownBlocks < minCooldown || newCooldownBlocks > maxCooldown) {
            revert UnllooErrors.InvalidDuration(newCooldownBlocks, minCooldown, maxCooldown);
        }
        if (newCooldownBlocks == cooldownBlocks) {
            revert UnllooErrors.InvalidDuration(newCooldownBlocks, cooldownBlocks, cooldownBlocks);
        }

        uint256 oldCooldownBlocks = cooldownBlocks;
        cooldownBlocks = newCooldownBlocks;

        emit CooldownBlocksUpdated(oldCooldownBlocks, newCooldownBlocks, block.number);
    }


    function addLiquidityPool(address token, uint256 minLoanAmount, uint256 maxLoanAmount)
        external
        override
        onlyOwner
    {
        if (token == address(0)) revert UnllooErrors.InvalidPool(address(0));
        if (pools[token].token != address(0)) revert UnllooErrors.PoolExists(token);

        _validateTokenDecimals(token);

        if (minLoanAmount == 0 || maxLoanAmount == 0) revert UnllooErrors.InvalidPoolLoanLimits(minLoanAmount, maxLoanAmount);
        if (minLoanAmount >= maxLoanAmount) revert UnllooErrors.InvalidPoolLoanLimits(minLoanAmount, maxLoanAmount);

        pools[token] = LiquidityPool({ token: token, totalLiquidity: 0, borrowedAmount: 0 });
        minLoanAmountPerPool[token] = minLoanAmount;
        maxLoanAmountPerPool[token] = maxLoanAmount;

        poolSupplyIndex[token] = INDEX_SCALE;

        // Set default rate curve for new pool
        _poolRateCurve[token] = RateCurveParams({
            baseRateBps: DEFAULT_BASE_RATE_BPS,
            optimalUtilizationBps: DEFAULT_OPTIMAL_UTILIZATION_BPS,
            slope1Bps: DEFAULT_SLOPE1_BPS,
            slope2Bps: DEFAULT_SLOPE2_BPS,
            protocolFeeBps: DEFAULT_PROTOCOL_FEE_BPS
        });

        emit PoolAdded(token, block.number);
    }

    function removeLiquidityPool(address token)
        external
        override
        onlyOwner
    {
        LiquidityPool memory pool = pools[token];
        if (pool.token == address(0)) revert UnllooErrors.InvalidPool(token);
        if (pool.totalLiquidity > 0) revert UnllooErrors.PoolNotEmpty(token);

        if (activeLoansPerPool[token] != 0 || unpaidDebtLoansPerPool[token] != 0) {
            revert UnllooErrors.ActiveLoansUsingPool(token);
        }

        delete pools[token];
        delete minLoanAmountPerPool[token];
        delete maxLoanAmountPerPool[token];
        delete poolSupplyIndex[token];
        delete poolUndistributedInterest[token];
        delete _poolRateCurve[token];

        emit PoolRemoved(token, block.number);
    }

    function updatePoolLoanLimits(address token, uint256 minLoanAmount, uint256 maxLoanAmount)
        external
        override
        onlyOwner
    {
        if (token == address(0) || pools[token].token == address(0)) revert UnllooErrors.InvalidPool(token);
        if (minLoanAmount == 0 || maxLoanAmount == 0) revert UnllooErrors.InvalidPoolLoanLimits(minLoanAmount, maxLoanAmount);
        if (minLoanAmount >= maxLoanAmount) revert UnllooErrors.InvalidPoolLoanLimits(minLoanAmount, maxLoanAmount);

        minLoanAmountPerPool[token] = minLoanAmount;
        maxLoanAmountPerPool[token] = maxLoanAmount;

        emit PoolLoanLimitsUpdated(token, minLoanAmount, maxLoanAmount, block.number);
    }

    function updatePoolRateCurve(
        address token,
        uint256 baseRateBps,
        uint256 optimalUtilizationBps,
        uint256 slope1Bps,
        uint256 slope2Bps,
        uint256 protocolFeeBps
    )
        external
        override
        onlyOwner
        validPool(token)
    {
        // Validation: baseRateBps max 10%
        if (baseRateBps > 1000) {
            revert UnllooErrors.InvalidRateCurveParam(token, "baseRateBps", baseRateBps);
        }

        // Validation: optimalUtilizationBps between 50% and 95%
        if (optimalUtilizationBps < 5000 || optimalUtilizationBps > 9500) {
            revert UnllooErrors.InvalidRateCurveParam(token, "optimalUtilizationBps", optimalUtilizationBps);
        }

        // Validation: slope1Bps max 20%
        if (slope1Bps > 2000) {
            revert UnllooErrors.InvalidRateCurveParam(token, "slope1Bps", slope1Bps);
        }

        // Validation: slope2Bps max 100%
        if (slope2Bps > 10000) {
            revert UnllooErrors.InvalidRateCurveParam(token, "slope2Bps", slope2Bps);
        }

        // Validation: protocolFeeBps max 50%
        if (protocolFeeBps > 5000) {
            revert UnllooErrors.InvalidRateCurveParam(token, "protocolFeeBps", protocolFeeBps);
        }

        // Validation: max possible rate must not exceed MAX_BORROWER_RATE
        uint256 maxPossibleRate = baseRateBps + slope1Bps + slope2Bps;
        if (maxPossibleRate > MAX_BORROWER_RATE) {
            revert UnllooErrors.InvalidRateCurveParam(token, "totalMaxRate", maxPossibleRate);
        }

        _poolRateCurve[token] = RateCurveParams({
            baseRateBps: baseRateBps,
            optimalUtilizationBps: optimalUtilizationBps,
            slope1Bps: slope1Bps,
            slope2Bps: slope2Bps,
            protocolFeeBps: protocolFeeBps
        });

        emit InterestRatesUpdated(
            token,
            baseRateBps,
            optimalUtilizationBps,
            slope1Bps,
            slope2Bps,
            protocolFeeBps,
            block.number
        );
    }

    function getPoolRateCurve(address token)
        external
        view
        override
        returns (RateCurveParams memory)
    {
        return _poolRateCurve[token];
    }

    function getPoolLoanLimits(address token)
        external
        view
        override
        returns (uint256 minLoanAmount, uint256 maxLoanAmount)
    {
        return (minLoanAmountPerPool[token], maxLoanAmountPerPool[token]);
    }

    function withdrawProtocolFees(address token, uint256 amount)
        external
        override
        onlyOwner
        nonReentrant
        whenNotPaused
    {
        _validateNonZeroAddress(token);
        _validateNonZeroAmount(amount, protocolFees[token]);

        protocolFees[token] -= amount;
        address o = owner();
        _safeTransferExact(token, o, amount);
        emit ProtocolFeesWithdrawn(o, token, amount, block.number);
    }

    // ============ Internal: Simple Interest ============

    /// @notice Accrue simple interest on a loan
    /// @dev Simple interest: I = P * r * t
    ///      Updates loan.interestAccrued but NOT lastAccrualBlock
    ///      lastAccrualBlock is only updated when interest is fully settled (in _processInterestPayment)
    ///      This ensures continuous interest accrual regardless of principal payments
    ///      Uses multiply-first-divide-last pattern to avoid precision loss
    function _accrueLoanInterest(uint256 loanId) internal {
        Loan storage loan = loans[loanId];
        // Sentinel check: loan has no principal or rate set
        if (loan.principal == 0 || loan.borrowRateBps == 0) return;
        // Sentinel check: loan not yet started; no interest accrual
        if (loan.lastAccrualBlock == 0) return;

        uint256 blocksElapsed = block.number - loan.lastAccrualBlock;
        // Sentinel check: no blocks elapsed since last accrual
        if (blocksElapsed == 0) return;

        // Simple interest: I = P * r * t
        // r = rateBps / 10000 (annual rate in basis points)
        // t = blocksElapsed * BLOCK_TIME_SECONDS / secondsPerYear
        // Combined: I = P * rateBps * blocksElapsed * BLOCK_TIME_SECONDS / (10000 * secondsPerYear)
        // Multiply first, divide last to avoid precision loss
        uint256 secondsPerYear = 365 * 24 * 60 * 60;
        uint256 interest = (loan.principal * loan.borrowRateBps * blocksElapsed * BLOCK_TIME_SECONDS) / (10000 * secondsPerYear);

        loan.interestAccrued += interest;
        // DO NOT update lastAccrualBlock here - it's only updated when interest is fully settled
        // This ensures the accrual baseline persists across principal payments
    }

    /// @notice Calculate utilization-based borrow rate
    /// @dev Piecewise linear model based on pool utilization using per-pool parameters
    ///      Uses multiply-first-divide-last pattern to avoid precision loss
    /// @param token Token address of the pool
    /// @return rateBps Borrow rate in basis points
    function _calculateBorrowRate(address token) internal view returns (uint256 rateBps) {
        LiquidityPool memory pool = pools[token];
        if (pool.totalLiquidity == 0) return MIN_BORROWER_RATE;

        RateCurveParams memory curve = _poolRateCurve[token];

        // Calculate utilization: U = borrowedAmount * 10000 / totalLiquidity
        uint256 utilization = (pool.borrowedAmount * 10000) / pool.totalLiquidity;

        // Piecewise linear model (multiply first, divide last to avoid precision loss)
        if (utilization <= curve.optimalUtilizationBps) {
            // Below optimal: baseRate + (borrowedAmount * 10000 * slope1) / (totalLiquidity * optimalUtil)
            // This combines the utilization calculation with the slope calculation
            uint256 slopeContribution = (pool.borrowedAmount * 10000 * curve.slope1Bps) / 
                (pool.totalLiquidity * curve.optimalUtilizationBps);
            rateBps = curve.baseRateBps + slopeContribution;
        } else {
            // Above optimal: baseRate + slope1 + ((U - optimalUtil) * slope2) / (10000 - optimalUtil)
            uint256 excessUtil = utilization - curve.optimalUtilizationBps;
            uint256 remainingUtil = 10000 - curve.optimalUtilizationBps;
            // Multiply first: (excessUtil * slope2Bps) / remainingUtil
            uint256 excessContribution = (excessUtil * curve.slope2Bps) / remainingUtil;
            rateBps = curve.baseRateBps + curve.slope1Bps + excessContribution;
        }

        // Clamp to min/max bounds
        if (rateBps < MIN_BORROWER_RATE) rateBps = MIN_BORROWER_RATE;
        if (rateBps > MAX_BORROWER_RATE) rateBps = MAX_BORROWER_RATE;

        return rateBps;
    }

    /// @notice Get accrued interest for a loan (view function)
    /// @dev Calculates interest without modifying state
    ///      Uses multiply-first-divide-last pattern to avoid precision loss
    function _getAccruedInterest(uint256 loanId) internal view returns (uint256) {
        Loan memory loan = loans[loanId];
        // Sentinel check: loan has no principal or rate set
        if (loan.principal == 0 || loan.borrowRateBps == 0) return loan.interestAccrued;
        // Sentinel check: loan not yet started; return existing accrued interest
        if (loan.lastAccrualBlock == 0) return loan.interestAccrued;

        uint256 blocksElapsed = block.number - loan.lastAccrualBlock;
        // Sentinel check: no blocks elapsed since last accrual
        if (blocksElapsed == 0) return loan.interestAccrued;

        // Multiply first, divide last to avoid precision loss
        uint256 secondsPerYear = 365 * 24 * 60 * 60;
        uint256 newInterest = (loan.principal * loan.borrowRateBps * blocksElapsed * BLOCK_TIME_SECONDS) / (10000 * secondsPerYear);
        return loan.interestAccrued + newInterest;
    }

    // ============ Internal: Lender index ============
    /// @dev Distributes pending interest to the supply index
    /// @notice Explicitly tracks rounding dust to maintain exact accounting and prevent precision loss.
    ///         This function handles the divide-before-multiply pattern by explicitly calculating
    ///         and preserving any rounding dust that would otherwise be lost.
    /// @param token The token address for the pool
    function _distributePendingInterest(address token) internal {
        uint256 pending = poolUndistributedInterest[token];
        if (pending == 0) return;

        uint256 tl = pools[token].totalLiquidity;
        if (tl == 0) return;

        // Calculate index delta: (pending * INDEX_SCALE) / tl
        uint256 delta = (pending * INDEX_SCALE) / tl;
        if (delta == 0) return;

        // Calculate actual distributed amount: (delta * tl) / INDEX_SCALE
        // This divide-before-multiply pattern is intentional for index-based distribution,
        // but we MUST track the rounding dust to prevent permanent loss
        uint256 distributed = (delta * tl) / INDEX_SCALE;

        // CRITICAL: Explicitly calculate and preserve rounding dust
        // Without this, dust would be permanently lost, causing long-term lender underpayment
        uint256 dust = pending - distributed;
        poolUndistributedInterest[token] = dust;
        poolSupplyIndex[token] += delta;
    }

    function _updateLenderAccrual(address lender, address token) internal {
        LenderPosition memory pos = lenderPositions[lender][token];
        if (pos.depositedAmount == 0) {
            lenderSupplyIndex[lender][token] = poolSupplyIndex[token];
            return;
        }

        uint256 idx = poolSupplyIndex[token];
        uint256 lenderIdx = lenderSupplyIndex[lender][token];
        if (lenderIdx == 0) lenderIdx = idx;

        if (idx > lenderIdx) {
            uint256 delta = idx - lenderIdx;
            uint256 addAccrued = (pos.depositedAmount * delta) / INDEX_SCALE;
            if (addAccrued > 0) lenderAccruedInterest[lender][token] += addAccrued;
        }

        lenderSupplyIndex[lender][token] = idx;
    }

    /// @dev Distributes interest to lenders via supply index
    /// @notice Explicitly tracks rounding dust to maintain exact accounting and prevent precision loss.
    ///         This function handles the divide-before-multiply pattern by explicitly calculating
    ///         and preserving any rounding dust that would otherwise be lost.
    /// @param token The token address for the pool
    /// @param amount The interest amount to distribute
    function _distributeInterestToLenders(address token, uint256 amount) internal {
        if (amount == 0) return;
        uint256 tl = pools[token].totalLiquidity;
        if (tl == 0) {
            // No liquidity: store entire amount as undistributed for future distribution
            poolUndistributedInterest[token] += amount;
            return;
        }

        // Calculate index delta: (amount * INDEX_SCALE) / tl
        uint256 delta = (amount * INDEX_SCALE) / tl;
        if (delta == 0) {
            // Delta too small: store entire amount as undistributed for future distribution
            poolUndistributedInterest[token] += amount;
            return;
        }

        // Calculate actual distributed amount: (delta * tl) / INDEX_SCALE
        // This divide-before-multiply pattern is intentional for index-based distribution,
        // but we MUST track the rounding dust to prevent permanent loss
        uint256 distributed = (delta * tl) / INDEX_SCALE;

        // CRITICAL: Explicitly calculate and preserve rounding dust
        // Without this, dust would be permanently lost, causing long-term lender underpayment
        uint256 dust = amount - distributed;
        poolUndistributedInterest[token] += dust;

        poolSupplyIndex[token] += delta;
    }

    // ============ Internal: Status transitions ============
    function _transitionToUnpaidDebt(uint256 loanId, Loan storage loan, uint256 deadline) internal {
        if (loan.status != LoanStatus.Active) return;

        loan.status = LoanStatus.UnpaidDebt;
        loan.deadlineBlock = deadline;

        UnllooStatusArray.remove(_loansByStatus[LoanStatus.Active], _loanStatusIndex[LoanStatus.Active], loanId, LoanStatus.Active);
        UnllooStatusArray.add(_loansByStatus[LoanStatus.UnpaidDebt], _loanStatusIndex[LoanStatus.UnpaidDebt], loanId, LoanStatus.UnpaidDebt);

        unpaidDebtLoanCount[loan.borrower] += 1;

        if (_activeLoanByBorrower[loan.borrower] == loanId) _activeLoanByBorrower[loan.borrower] = 0;

        // per-pool counters
        address token = loan.token;
        if (activeLoansPerPool[token] > 0) activeLoansPerPool[token] -= 1;
        unpaidDebtLoansPerPool[token] += 1;

        emit LoanMovedToUnpaidDebt(loanId, loan.borrower, loan.deadlineBlock, block.number);
    }

    function _finalizeRepaid(uint256 loanId, Loan storage loan) internal {
        LoanStatus beforeStatus = loan.status;
        loan.status = LoanStatus.Repaid;

        if (beforeStatus == LoanStatus.UnpaidDebt && unpaidDebtLoanCount[loan.borrower] > 0) {
            unpaidDebtLoanCount[loan.borrower] -= 1;
        }

        if (_activeLoanByBorrower[loan.borrower] == loanId) {
            _activeLoanByBorrower[loan.borrower] = 0;
        }

        // per-pool counters
        address token = loan.token;
        if (beforeStatus == LoanStatus.Active) {
            if (activeLoansPerPool[token] > 0) activeLoansPerPool[token] -= 1;
        } else if (beforeStatus == LoanStatus.UnpaidDebt) {
            if (unpaidDebtLoansPerPool[token] > 0) unpaidDebtLoansPerPool[token] -= 1;
        }

        UnllooStatusArray.remove(_loansByStatus[beforeStatus], _loanStatusIndex[beforeStatus], loanId, beforeStatus);
        UnllooStatusArray.add(_loansByStatus[LoanStatus.Repaid], _loanStatusIndex[LoanStatus.Repaid], loanId, LoanStatus.Repaid);
    }

    // ============ Internal: Transfer helpers (strict ERC20) ============
    function _safeTransferFromExact(address token, address from, address to, uint256 amount) internal {
        uint256 beforeBal = IERC20(token).balanceOf(to);
        IERC20(token).safeTransferFrom(from, to, amount);
        uint256 afterBal = IERC20(token).balanceOf(to);
        if (afterBal - beforeBal != amount) revert UnllooErrors.UnsupportedTokenTransfer(token);
    }

    function _safeTransferExact(address token, address to, uint256 amount) internal {
        uint256 beforeFrom = IERC20(token).balanceOf(address(this));
        uint256 beforeTo = IERC20(token).balanceOf(to);
        IERC20(token).safeTransfer(to, amount);
        uint256 afterFrom = IERC20(token).balanceOf(address(this));
        uint256 afterTo = IERC20(token).balanceOf(to);
        if (beforeFrom - afterFrom != amount) revert UnllooErrors.UnsupportedTokenTransfer(token);
        if (afterTo - beforeTo != amount) revert UnllooErrors.UnsupportedTokenTransfer(token);
    }

    // ============ Internal Helper Functions ============
    function _getLoanLimits(address token)
        internal
        view
        returns (uint256 minLoanAmountToken, uint256 maxLoanAmountToken)
    {
        minLoanAmountToken = minLoanAmountPerPool[token];
        maxLoanAmountToken = maxLoanAmountPerPool[token];
        if (minLoanAmountToken == 0 || maxLoanAmountToken == 0) {
            revert UnllooErrors.InvalidPoolLoanLimits(minLoanAmountToken, maxLoanAmountToken);
        }
    }

    function _validateNonZeroAddress(address addr) internal pure {
        if (addr == address(0)) revert UnllooErrors.InvalidPool(address(0));
    }

    function _validateNonZeroAmount(uint256 amount, uint256 maxAmount) internal pure {
        if (amount == 0 || amount > maxAmount) revert UnllooErrors.InvalidAmount(amount, 1, maxAmount);
    }

    function _validateTokenDecimals(address token) internal view {
        try IERC20Metadata(token).decimals() returns (uint8 decimals) {
            if (decimals < 6 || decimals > 18) revert UnllooErrors.InvalidPool(token);
        } catch {
            revert UnllooErrors.InvalidPool(token);
        }
    }

    // ============ Receive Function ============
    receive() external payable whenNotPaused nonReentrant {
        if (msg.value == 0) revert UnllooErrors.InvalidAmount(0, 1, type(uint256).max);

        protocolFees[address(0)] += msg.value;
        emit ETHReceived(msg.sender, msg.value, block.number);
    }
}

contracts/utils/ReentrancyGuardUpgradeab.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "@openzeppelin/contracts-upgradeable/proxy/utils/Initializable.sol";

/**
 * @title ReentrancyGuardUpgradeable
 * @notice Minimal upgradeable reentrancy guard compatible with proxy deployments.
 * @dev This is a compatibility shim for OpenZeppelin Contracts Upgradeable v5.5+
 *      where ReentrancyGuardUpgradeable was deprecated/removed.
 *
 *      API is intentionally aligned with OZ's historical ReentrancyGuardUpgradeable:
 *      - __ReentrancyGuard_init()
 *      - __ReentrancyGuard_init_unchained()
 *      - nonReentrant modifier
 */
abstract contract ReentrancyGuardUpgradeable is Initializable {
    // Booleans are more expensive than uint256 or any type that takes up a full
    // word because each write emits an extra SLOAD to first read the slot's
    // contents, replace the bits taken up by the boolean, and then write back.
    uint256 private constant _NOT_ENTERED = 1;
    uint256 private constant _ENTERED = 2;

    uint256 private _status;

    error ReentrancyGuardReentrantCall();

    function __ReentrancyGuard_init() internal onlyInitializing {
        __ReentrancyGuard_init_unchained();
    }

    function __ReentrancyGuard_init_unchained() internal onlyInitializing {
        _status = _NOT_ENTERED;
    }

    modifier nonReentrant() {
        if (_status == _ENTERED) revert ReentrancyGuardReentrantCall();
        _status = _ENTERED;
        _;
        _status = _NOT_ENTERED;
    }

    // Gap for future upgrades (keep consistent with OZ pattern)
    uint256[49] private __gap;
}
